def reconcile_corpus(
    mdm_hub,
    vector_store,
    sync_service,
    entity_domains: list[str],
) -> dict:
    """Compare MDM hub state against vector store metadata. Return diff report."""
    report = {"missing": [], "version_behind": [], "orphaned": []}

    # Build index: mdm_id -> current_version from the MDM hub
    mdm_current: dict[str, int] = {}
    for domain in entity_domains:
        for record in mdm_hub.list_active_records(domain=domain):
            mdm_current[record.mdm_id] = record.version

    # Build index: mdm_id -> max indexed version from vector store metadata
    vs_indexed: dict[str, int] = {}
    for chunk_meta in vector_store.scan_metadata(fields=["mdm_id", "version"]):
        mdm_id = chunk_meta["mdm_id"]
        version = chunk_meta["version"]
        vs_indexed[mdm_id] = max(vs_indexed.get(mdm_id, 0), version)

    for mdm_id, current_version in mdm_current.items():
        indexed_version = vs_indexed.get(mdm_id)
        if indexed_version is None:
            report["missing"].append(mdm_id)
        elif indexed_version < current_version:
            report["version_behind"].append((mdm_id, indexed_version, current_version))

    # Find orphaned chunks: in vector store but not in MDM hub
    for mdm_id in vs_indexed:
        if mdm_id not in mdm_current:
            report["orphaned"].append(mdm_id)

    return report
